Here is a complete, single-file HTML solution using **Three.js**. This code generates a stylized, low-poly 3D house with a grassy ground, a blue sky, and a rotating camera to showcase the model.

You can save the code below as an `.html` file (e.g., `house.html`) and open it in any modern web browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">3D House Model (Three.js)</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // --- 1. Scene Setup ---
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(8, 6, 8);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        document.body.appendChild(renderer.domElement);

        // --- 2. Lighting ---
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1.5);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // --- 3. Materials ---
        const materials = {
            grass: new THREE.MeshStandardMaterial({ color: 0x55aa55 }),
            wall: new THREE.MeshStandardMaterial({ color: 0xeeeeee }),
            roof: new THREE.MeshStandardMaterial({ color: 0x8B4513 }), // SaddleBrown
            window: new THREE.MeshStandardMaterial({ color: 0x87CEEB, emissive: 0x87CEEB, emissiveIntensity: 0.5 }),
            door: new THREE.MeshStandardMaterial({ color: 0x8B0000 })
        };

        // --- 4. Building the House ---
        const houseGroup = new THREE.Group();

        // A. Ground
        const groundGeo = new THREE.PlaneGeometry(50, 50);
        const ground = new THREE.Mesh(groundGeo, materials.grass);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // B. Main Body (Cube)
        const bodyGeo = new THREE.BoxGeometry(4, 3, 4);
        const body = new THREE.Mesh(bodyGeo, materials.wall);
        body.position.y = 1.5;
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // C. Roof (Pyramid)
        const roofGeo = new THREE.ConeGeometry(3.5, 2, 4);
        const roof = new THREE.Mesh(roofGeo, materials.roof);
        roof.position.y = 4; // Sit on top of body
        roof.rotation.y = Math.PI / 4; // Align square base with cube
        roof.castShadow = true;
        houseGroup.add(roof);

        // D. Windows
        const windowGeo = new THREE.BoxGeometry(0.8, 0.8, 0.1);

        // Front Window
        const win1 = new THREE.Mesh(windowGeo, materials.window);
        win1.position.set(0, 1.5, 2.05);
        houseGroup.add(win1);

        // Side Window
        const win2 = new THREE.Mesh(windowGeo, materials.window);
        win2.position.set(2.05, 1.5, 0);
        houseGroup.add(win2);

        // E. Door
        const doorGeo = new THREE.BoxGeometry(1, 2, 0.1);
        const door = new THREE.Mesh(doorGeo, materials.door);
        door.position.set(0, 1, 2.05);
        houseGroup.add(door);

        // F. Chimney
        const chimneyGeo = new THREE.BoxGeometry(0.6, 1.5, 0.6);
        const chimney = new THREE.Mesh(chimneyGeo, materials.wall);
        chimney.position.set(1.5, 4.5, 0);
        chimney.castShadow = true;
        houseGroup.add(chimney);

        scene.add(houseGroup);

        // --- 5. Controls & Animation ---
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.target.set(0, 1.5, 0);

        // Simple animation loop
        function animate() {
            requestAnimationFrame(animate);

            // Slowly rotate the house for effect
            houseGroup.rotation.y += 0.002;

            controls.update();
            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  Copy the code block above.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  Double-click `house.html` to open it in your browser.

### Features included:
*   **Procedural Geometry:** The house is built using basic geometric shapes (Box, Cone, Plane) grouped together.
*   **Lighting & Shadows:** Includes a directional light that casts realistic shadows on the ground.
*   **Interactivity:** You can click and drag to rotate the camera, scroll to zoom, and right-click to pan (using `OrbitControls`).
*   **Animation:** The house slowly rotates on its own axis to show off the 3D depth.
